1	import { eq } from "@tanstack/db";
2	import { useLiveQuery } from "@tanstack/react-db";
3	import { useQueries, useQueryClient } from "@tanstack/react-query";
4	import { useCallback, useEffect, useMemo, useRef, useState } from "react";
5	import { useRelayUrl } from "renderer/hooks/useRelayUrl";
6	import { getHostServiceClientByUrl } from "renderer/lib/host-service-client";
7	import { useDashboardSidebarState } from "renderer/routes/_authenticated/hooks/useDashboardSidebarState";
8	import { useCollections } from "renderer/routes/_authenticated/providers/CollectionsProvider";
9	import {
10		APP_LAUNCH_ID,
11		formatSnoozeRemaining,
12		getWorkspaceSidebarBucket,
13		isAutoIncludedLocalMainWorkspace,
14	} from "renderer/routes/_authenticated/providers/CollectionsProvider/dashboardSidebarLocal";
15	import { useHostWorkspaces } from "renderer/routes/_authenticated/providers/HostWorkspacesProvider";
16	import { useLocalHostService } from "renderer/routes/_authenticated/providers/LocalHostServiceProvider";
17	import { useWorkspaceTransactionsStore } from "renderer/stores/workspace-creates";
18	import type {
19		DashboardSidebarProject,
20		DashboardSidebarProjectChild,
21		DashboardSidebarSection,
22		DashboardSidebarWorkspace,
23	} from "../../types";
24	import {
25		derivePullRequestQueryTargets,
26		getDashboardSidebarPullRequestQueryKey,
27		type PullRequestQueryTarget,
28	} from "./derivePullRequestQueryTargets";
29	
30	const MAIN_WORKSPACE_TAB_ORDER = Number.MIN_SAFE_INTEGER;
31	
32	type SidebarPullRequest = DashboardSidebarWorkspace["pullRequest"];
33	type PullRequestWorkspaceRow = {
34		workspaceId: string;
35		pullRequest: SidebarPullRequest;
36	};
37	
38	function haveSameProjects(
39		left: DashboardSidebarProject[],
40		right: DashboardSidebarProject[],
41	): boolean {
42		return (
43			left.length === right.length &&
44			left.every((project, index) => project === right[index])
45		);
46	}
47	
48	function getPullRequestRowsFingerprint(
49		rows: PullRequestWorkspaceRow[],
50	): string {
51		return JSON.stringify(
52			rows
53				.map((row) => [row.workspaceId, row.pullRequest] as const)
54				.sort(([leftWorkspaceId], [rightWorkspaceId]) =>
55					leftWorkspaceId.localeCompare(rightWorkspaceId),
56				),
57		);
58	}
59	
60	function getDashboardSidebarProjectFingerprint(
61		project: DashboardSidebarProject,
62	): string {
63		return JSON.stringify(project);
64	}
65	
66	function useStablePullRequestsByWorkspaceId(
67		rows: PullRequestWorkspaceRow[] | undefined,
68	): Map<string, SidebarPullRequest> {
69		const previousRef = useRef<{
70			fingerprint: string;
71			map: Map<string, SidebarPullRequest>;
72		} | null>(null);
73	
74		return useMemo(() => {
75			const nextRows = rows ?? [];
76			const fingerprint = getPullRequestRowsFingerprint(nextRows);
77			const previous = previousRef.current;
78			if (previous?.fingerprint === fingerprint) {
79				return previous.map;
80			}
81	
82			const map = new Map(
83				nextRows.map((workspace) => [
84					workspace.workspaceId,
85					workspace.pullRequest,
86				]),
87			);
88			previousRef.current = { fingerprint, map };
89			return map;
90		}, [rows]);
91	}
92	
93	function useStableDashboardSidebarProjects(
94		projects: DashboardSidebarProject[],
95	): DashboardSidebarProject[] {
96		const previousRef = useRef<{
97			projects: DashboardSidebarProject[];
98			byId: Map<
99				string,
100				{ fingerprint: string; project: DashboardSidebarProject }
101			>;
102		} | null>(null);
103	
104		return useMemo(() => {
105			const previous = previousRef.current;
106			const nextById = new Map<
107				string,
108				{ fingerprint: string; project: DashboardSidebarProject }
109			>();
110			const nextProjects = projects.map((project) => {
111				const fingerprint = getDashboardSidebarProjectFingerprint(project);
112				const previousProject = previous?.byId.get(project.id);
113				const stableProject =
114					previousProject?.fingerprint === fingerprint
115						? previousProject.project
116						: project;
117	
118				nextById.set(project.id, { fingerprint, project: stableProject });
119				return stableProject;
120			});
121	
122			if (previous && haveSameProjects(previous.projects, nextProjects)) {
123				previousRef.current = { projects: previous.projects, byId: nextById };
124				return previous.projects;
125			}
126	
127			previousRef.current = { projects: nextProjects, byId: nextById };
128			return nextProjects;
129		}, [projects]);
130	}
131	
132	export function useDashboardSidebarData() {
133		const collections = useCollections();
134		const { machineId, activeHostUrl } = useLocalHostService();
135		const relayUrl = useRelayUrl();
136		const { toggleProjectCollapsed, unsnoozeWorkspace } =
137			useDashboardSidebarState();
138		const queryClient = useQueryClient();
139		const workspaceTransactionsById = useWorkspaceTransactionsStore(
140			(state) => state.byWorkspaceId,
141		);
142	
143		const { data: hosts = [] } = useLiveQuery(
144			(q) =>
145				q.from({ hosts: collections.v2Hosts }).select(({ hosts }) => ({
146					organizationId: hosts.organizationId,
147					machineId: hosts.machineId,
148					isOnline: hosts.isOnline,
149				})),
150			[collections],
151		);
152		const hostsByMachineId = useMemo(
153			() => new Map(hosts.map((host) => [host.machineId, host])),
154			[hosts],
155		);
156	
157		const { data: rawSidebarProjects = [] } = useLiveQuery(
158			(q) =>
159				q
160					.from({ sidebarProjects: collections.v2SidebarProjects })
161					.innerJoin(
162						{ projects: collections.v2Projects },
163						({ sidebarProjects, projects }) =>
164							eq(sidebarProjects.projectId, projects.id),
165					)
166					.leftJoin(
167						{ repos: collections.githubRepositories },
168						({ projects, repos }) => eq(projects.githubRepositoryId, repos.id),
169					)
170					.orderBy(({ sidebarProjects }) => sidebarProjects.tabOrder, "asc")
171					.select(({ sidebarProjects, projects, repos }) => ({
172						id: projects.id,
173						name: projects.name,
174						slug: projects.slug,
175						githubRepositoryId: projects.githubRepositoryId,
176						githubOwner: repos?.owner ?? null,
177						githubRepoName: repos?.name ?? null,
178						iconUrl: projects.iconUrl,
179						createdAt: projects.createdAt,
180						updatedAt: projects.updatedAt,
181						isCollapsed: sidebarProjects.isCollapsed,
182						isPinned: sidebarProjects.isPinned,
183						showSnoozed: sidebarProjects.showSnoozed,
184						showArchived: sidebarProjects.showArchived,
185						snoozedCollapsed: sidebarProjects.snoozedCollapsed,
186						archivedCollapsed: sidebarProjects.archivedCollapsed,
187						// (RECYCLE-BIN) reveal + collapse for the per-project Recycle Bin.
188						showDeleted: sidebarProjects.showDeleted,
189						deletedCollapsed: sidebarProjects.deletedCollapsed,
190					})),
191			[collections],
192		);
193	
194		const sidebarProjects = useMemo(
195			() =>
196				rawSidebarProjects.map((project) => ({
197					...project,
198					githubOwner: project.githubOwner ?? null,
199					githubRepoName: project.githubRepoName ?? null,
200					// Heal legacy project rows persisted before the reveal flags existed
201					// (they read back undefined despite the boolean type).
202					isPinned: project.isPinned ?? false,
203					showSnoozed: project.showSnoozed ?? false,
204					showArchived: project.showArchived ?? false,
205					snoozedCollapsed: project.snoozedCollapsed ?? false,
206					archivedCollapsed: project.archivedCollapsed ?? false,
207					// (RECYCLE-BIN) heal rows persisted before the bin flags existed.
208					showDeleted: project.showDeleted ?? false,
209					deletedCollapsed: project.deletedCollapsed ?? false,
210				})),
211			[rawSidebarProjects],
212		);
213	
214		const { data: sidebarSections = [] } = useLiveQuery(
215			(q) =>
216				q
217					.from({ sidebarSections: collections.v2SidebarSections })
218					.orderBy(({ sidebarSections }) => sidebarSections.tabOrder, "asc")
219					.select(({ sidebarSections }) => ({
220						id: sidebarSections.sectionId,
221						projectId: sidebarSections.projectId,
222						name: sidebarSections.name,
223						createdAt: sidebarSections.createdAt,
224						isCollapsed: sidebarSections.isCollapsed,
225						tabOrder: sidebarSections.tabOrder,
226						color: sidebarSections.color,
227					})),
228			[collections],
229		);
230	
231		const { workspaces: hostWorkspaces } = useHostWorkspaces();
232		const hostWorkspacesById = useMemo(
233			() => new Map(hostWorkspaces.map((workspace) => [workspace.id, workspace])),
234			[hostWorkspaces],
235		);
236	
237		const { data: sidebarLocalStateRows = [] } = useLiveQuery(
238			(q) =>
239				q
240					.from({ sidebarWorkspaces: collections.v2WorkspaceLocalState })
241					.orderBy(
242						({ sidebarWorkspaces }) => sidebarWorkspaces.sidebarState.tabOrder,
243						"asc",
244					)
245					.select(({ sidebarWorkspaces }) => ({
246						workspaceId: sidebarWorkspaces.workspaceId,
247						projectId: sidebarWorkspaces.sidebarState.projectId,
248						tabOrder: sidebarWorkspaces.sidebarState.tabOrder,
249						sectionId: sidebarWorkspaces.sidebarState.sectionId,
250						isHidden: sidebarWorkspaces.sidebarState.isHidden,
251						snoozeUntil: sidebarWorkspaces.sidebarState.snoozeUntil,
252						snoozeLaunchId: sidebarWorkspaces.sidebarState.snoozeLaunchId,
253						archivedAt: sidebarWorkspaces.sidebarState.archivedAt,
254						// (KANBAN COMPLETED) must be projected or the bucket classifier
255						// below can't see it — completed rows are also isHidden and would
256						// misclassify as "archived" (surfacing under the Archived section).
257						completedAt: sidebarWorkspaces.sidebarState.completedAt,
258						// (RECYCLE-BIN) likewise projected so the classifier buckets it
259						// "deleted" (deletedAt is checked first) and the Recycle Bin section
260						// can sort by it / apply the retention window.
261						deletedAt: sidebarWorkspaces.sidebarState.deletedAt,
262					})),
263			[collections],
264		);
265		const rawSidebarWorkspaces = useMemo(
266			() =>
267				sidebarLocalStateRows.flatMap((localState) => {
268					const workspace = hostWorkspacesById.get(localState.workspaceId);
269					if (!workspace) return [];
270					return [
271						{
272							id: workspace.id,
273							projectId: localState.projectId,
274							hostId: workspace.hostId,
275							type: workspace.type,
276							name: workspace.name,
277							branch: workspace.branch,
278							taskId: workspace.taskId,
279							createdAt: workspace.createdAt,
280							updatedAt: workspace.updatedAt,
281							tabOrder: localState.tabOrder,
282							sectionId: localState.sectionId,
283							isHidden: localState.isHidden,
284						},
285					];
286				}),
287			[hostWorkspacesById, sidebarLocalStateRows],
288		);
289		const rawSidebarWorkspacesWithHostStatus = useMemo(
290			() =>
291				rawSidebarWorkspaces.map((workspace) => ({
292					...workspace,
293					hostIsOnline: hostsByMachineId.get(workspace.hostId)?.isOnline ?? false,
294					pendingTransaction: workspaceTransactionsById[workspace.id] ?? null,
295				})),
296			[hostsByMachineId, rawSidebarWorkspaces, workspaceTransactionsById],
297		);
298	
299		// Re-evaluate snooze expiry on a coarse timer so a snoozed thread pops back
300		// into the active lane shortly after its deadline. The ticker only runs while
301		// at least one row carries a snooze, so an idle sidebar isn't churning.
302		const [nowMs, setNowMs] = useState(() => Date.now());
303		// Gate the ticker on a TIMED snooze only. An "until next launch" snooze has no
304		// wall-clock deadline (it clears on relaunch via APP_LAUNCH_ID), so counting it
305		// here would keep the interval running forever doing nothing.
306		const hasPendingSnooze = useMemo(
307			() =>
308				rawSidebarWorkspaces.some((workspace) => workspace.snoozeUntil != null),
309			[rawSidebarWorkspaces],
310		);
311		useEffect(() => {
312			if (!hasPendingSnooze) return;
313			const interval = setInterval(() => setNowMs(Date.now()), 60_000);
314			return () => clearInterval(interval);
315		}, [hasPendingSnooze]);
316	
317		// Ids whose snooze expired by TIMER (not via manual "Unsnooze now") — only
318		// these flash the just-returned highlight when they re-enter the active lane.
319		const autoReturnedIdsRef = useRef<Set<string>>(new Set());
320	
321		// Lazily clear snooze fields once they expire (a past deadline, or an
322		// "until next launch" snooze from a previous launch) so stale markers don't
323		// accumulate and a returned thread carries no leftover snooze state.
324		useEffect(() => {
325			const expiredIds: string[] = [];
326			for (const workspace of rawSidebarWorkspaces) {
327				const staleLaunch =
328					workspace.snoozeLaunchId != null &&
329					workspace.snoozeLaunchId !== APP_LAUNCH_ID;
330				const expiredTimer =
331					typeof workspace.snoozeUntil === "number" &&
332					workspace.snoozeUntil <= nowMs;
333				if (staleLaunch || expiredTimer) {
334					expiredIds.push(workspace.id);
335					// Timer expiry is an auto-return (flashes); a stale-launch return on
336					// relaunch is not, to avoid a burst of highlights at startup.
337					if (expiredTimer) autoReturnedIdsRef.current.add(workspace.id);
338				}
339			}
340			if (expiredIds.length === 0) return;
341			for (const id of expiredIds) unsnoozeWorkspace(id);
342		}, [nowMs, rawSidebarWorkspaces, unsnoozeWorkspace]);
343	
344		const {
345			sidebarWorkspaces,
346			snoozedSidebarWorkspaces,
347			archivedSidebarWorkspaces,
348			deletedSidebarWorkspaces,
349		} = useMemo(() => {
350			type SidebarWorkspaceRow =
351				(typeof rawSidebarWorkspacesWithHostStatus)[number];
352			const active: SidebarWorkspaceRow[] = [];
353			const snoozed: SidebarWorkspaceRow[] = [];
354			const archived: SidebarWorkspaceRow[] = [];
355			const deleted: SidebarWorkspaceRow[] = [];
356			for (const workspace of rawSidebarWorkspacesWithHostStatus) {
357				// Single source of truth: getWorkspaceSidebarBucket reads the row's
358				// type. A removed non-main thread surfaces under Archived; a master card
359				// removed now archives too (archivedAt), while a LEGACY hidden main
360				// (isHidden, no timestamp) stays hidden — matching ensureSidebarWorkspaceRecord.
361				switch (getWorkspaceSidebarBucket(workspace, nowMs)) {
362					case "deleted":
363						// (RECYCLE-BIN) soft-deleted: surfaces ONLY in the project's Recycle
364						// Bin, never in the active lane / Snoozed / Archived / Completed.
365						deleted.push(workspace);
366						break;
367					case "archived":
368						archived.push(workspace);
369						break;
370					case "snoozed":
371						snoozed.push(workspace);
372						break;
373					case "hidden":
374						// Removed main/pinned workspace (isHidden, not archived): excluded
375						// from the active lane entirely — not shown anywhere, not resurrected.
376						break;
377					case "completed":
378						// (KANBAN COMPLETED) no sidebar surface at all — the kanban board's
379						// Completed column is the thread's only surface. Falling through to
380						// default would resurrect it into the ACTIVE lane.
381						break;
382					default:
383						active.push(workspace);
384				}
385			}
386			return {
387				sidebarWorkspaces: active,
388				snoozedSidebarWorkspaces: snoozed,
389				archivedSidebarWorkspaces: archived,
390				deletedSidebarWorkspaces: deleted,
391			};
392		}, [rawSidebarWorkspacesWithHostStatus, nowMs]);
393	
394		// Flash a subtle one-shot highlight on threads that just AUTO-returned from
395		// snooze (timer expiry flipped them snoozed -> active). Manual "Unsnooze now"
396		// is excluded — only ids the expiry ticker marked in autoReturnedIdsRef flash.
397		// Removal timers are owned by a ref-keyed map (not the effect's cleanup) so an
398		// unrelated re-render can't cancel a fade and strand the highlight.
399		const previousSnoozedIdsRef = useRef<Set<string>>(new Set());
400		const [justReturnedIds, setJustReturnedIds] = useState<ReadonlySet<string>>(
401			() => new Set(),
402		);
403		const justReturnedTimersRef = useRef<
404			Map<string, ReturnType<typeof setTimeout>>
405		>(new Map());
406		useEffect(() => {
407			const currentSnoozed = new Set(
408				snoozedSidebarWorkspaces.map((workspace) => workspace.id),
409			);
410			const activeIds = new Set(
411				sidebarWorkspaces.map((workspace) => workspace.id),
412			);
413			const returned: string[] = [];
414			for (const id of previousSnoozedIdsRef.current) {
415				if (
416					!currentSnoozed.has(id) &&
417					activeIds.has(id) &&
418					autoReturnedIdsRef.current.has(id)
419				) {
420					returned.push(id);
421					autoReturnedIdsRef.current.delete(id);
422				}
423			}
424			previousSnoozedIdsRef.current = currentSnoozed;
425			if (returned.length === 0) return;
426			setJustReturnedIds((previous) => {
427				const next = new Set(previous);
428				for (const id of returned) next.add(id);
429				return next;
430			});
431			const timers = justReturnedTimersRef.current;
432			for (const id of returned) {
433				const existing = timers.get(id);
434				if (existing) clearTimeout(existing);
435				timers.set(
436					id,
437					setTimeout(() => {
438						timers.delete(id);
439						setJustReturnedIds((previous) => {
440							if (!previous.has(id)) return previous;
441							const next = new Set(previous);
442							next.delete(id);
443							return next;
444						});
445					}, 3_000),
446				);
447			}
448		}, [snoozedSidebarWorkspaces, sidebarWorkspaces]);
449		// Clear any pending highlight timers only on unmount.
450		useEffect(() => {
451			const timers = justReturnedTimersRef.current;
452			return () => {
453				for (const timeout of timers.values()) clearTimeout(timeout);
454				timers.clear();
455			};
456		}, []);
457	
458		const localStateWorkspaceIds = useMemo(
459			() => new Set(rawSidebarWorkspaces.map((workspace) => workspace.id)),
460			[rawSidebarWorkspaces],
461		);
462	
463		const rawLocalMainWorkspaces = useMemo(
464			() =>
465				hostWorkspaces
466					.filter((workspace) => workspace.type === "main")
467					.map((workspace) => ({
468						id: workspace.id,
469						projectId: workspace.projectId,
470						hostId: workspace.hostId,
471						type: workspace.type,
472						name: workspace.name,
473						branch: workspace.branch,
474						taskId: workspace.taskId,
475						createdAt: workspace.createdAt,
476						updatedAt: workspace.updatedAt,
477						tabOrder: MAIN_WORKSPACE_TAB_ORDER,
478						sectionId: null as string | null,
479					})),
480			[hostWorkspaces],
481		);
482		const localMainWorkspaces = useMemo(
483			() =>
484				rawLocalMainWorkspaces.map((workspace) => ({
485					...workspace,
486					hostIsOnline: hostsByMachineId.get(workspace.hostId)?.isOnline ?? false,
487					pendingTransaction: workspaceTransactionsById[workspace.id] ?? null,
488				})),
489			[hostsByMachineId, rawLocalMainWorkspaces, workspaceTransactionsById],
490		);
491	
492		const visibleSidebarWorkspaces = useMemo(() => {
493			const sidebarProjectIds = new Set(
494				sidebarProjects.map((project) => project.id),
495			);
496			const autoLocalMainWorkspaces = localMainWorkspaces.filter((workspace) =>
497				isAutoIncludedLocalMainWorkspace(workspace, {
498					localStateWorkspaceIds,
499					sidebarProjectIds,
500					machineId,
501				}),
502			);
503	
504			return [...autoLocalMainWorkspaces, ...sidebarWorkspaces];
505		}, [
506			localMainWorkspaces,
507			localStateWorkspaceIds,
508			machineId,
509			sidebarProjects,
510			sidebarWorkspaces,
511		]);
512	
513		const pullRequestQueryTargets = useMemo<PullRequestQueryTarget[]>(
514			() =>
515				derivePullRequestQueryTargets({
516					activeHostUrl,
517					hosts,
518					machineId,
519					relayUrl,
520					workspaces: visibleSidebarWorkspaces,
521				}),
522			[activeHostUrl, hosts, machineId, relayUrl, visibleSidebarWorkspaces],
523		);
524	
525		const pullRequestQueries = useQueries({
526			queries: pullRequestQueryTargets.map((target) => ({
527				queryKey: getDashboardSidebarPullRequestQueryKey(target),
528				refetchInterval: 10_000,
529				queryFn: async () => {
530					const client = getHostServiceClientByUrl(target.hostUrl);
531					return client.pullRequests.getByWorkspaces.query({
532						workspaceIds: target.workspaceIds,
533					});
534				},
535			})),
536		});
537	
538		const pullRequestRows = useMemo<PullRequestWorkspaceRow[]>(() => {
539			const rows: PullRequestWorkspaceRow[] = [];
540			for (const query of pullRequestQueries) {
541				const data = query.data;
542				if (!data) continue;
543				for (const row of data.workspaces) {
544					rows.push({
545						workspaceId: row.workspaceId,
546						pullRequest: row.pullRequest,
547					});
548				}
549			}
550			return rows;
551		}, [pullRequestQueries]);
552	
553		// Keep the latest hover-target inputs in a ref so refreshWorkspacePullRequest
554		// keeps a STABLE identity. Its inputs derive from the nowMs partition, so
555		// without this it would change every 60s tick and churn the onWorkspaceHover
556		// prop on every memoised row.
557		const pullRequestRefreshInputsRef = useRef({
558			visibleSidebarWorkspaces,
559			pullRequestQueryTargets,
560		});
561		pullRequestRefreshInputsRef.current = {
562			visibleSidebarWorkspaces,
563			pullRequestQueryTargets,
564		};
565	
566		const refreshWorkspacePullRequest = useCallback(
567			async (workspaceId: string) => {
568				const {
569					visibleSidebarWorkspaces: latestWorkspaces,
570					pullRequestQueryTargets: latestTargets,
571				} = pullRequestRefreshInputsRef.current;
572				const workspace = latestWorkspaces.find(
573					(candidate) => candidate.id === workspaceId,
574				);
575				if (!workspace) return;
576				const target = latestTargets.find(
577					(candidate) => candidate.machineId === workspace.hostId,
578				);
579				if (!target) return;
580	
581				const client = getHostServiceClientByUrl(target.hostUrl);
582				await client.pullRequests.refreshByWorkspaces.mutate({
583					workspaceIds: [workspaceId],
584				});
585				await queryClient.invalidateQueries({
586					queryKey: getDashboardSidebarPullRequestQueryKey(target),
587				});
588			},
589			[queryClient],
590		);
591	
592		const pullRequestsByWorkspaceId =
593			useStablePullRequestsByWorkspaceId(pullRequestRows);
594	
595		const computedGroups = useMemo<DashboardSidebarProject[]>(() => {
596			const projectsById = new Map<
597				string,
598				DashboardSidebarProject & {
599					sectionMap: Map<string, DashboardSidebarSection>;
600					childEntries: Array<{
601						tabOrder: number;
602						child: DashboardSidebarProjectChild;
603					}>;
604					orphanedWorkspaces: Array<{
605						tabOrder: number;
606						workspace: DashboardSidebarWorkspace;
607					}>;
608				}
609			>();
610	
611			for (const project of sidebarProjects) {
612				projectsById.set(project.id, {
613					...project,
614					children: [],
615					snoozedWorkspaces: [],
616					archivedWorkspaces: [],
617					// (RECYCLE-BIN) full, unfiltered bin contents; the section component
618					// applies the retention window and derives its header count from this
619					// array's length.
620					deletedWorkspaces: [],
621					sectionMap: new Map(),
622					childEntries: [],
623					orphanedWorkspaces: [],
624				});
625			}
626	
627			for (const section of sidebarSections) {
628				const project = projectsById.get(section.projectId);
629				if (!project) continue;
630	
631				const sidebarSection: DashboardSidebarSection = {
632					...section,
633					workspaces: [],
634				};
635	
636				project.sectionMap.set(section.id, sidebarSection);
637				project.childEntries.push({
638					tabOrder: section.tabOrder,
639					child: {
640						type: "section",
641						section: sidebarSection,
642					},
643				});
644			}
645	
646			for (const workspace of visibleSidebarWorkspaces) {
647				const project = projectsById.get(workspace.projectId);
648				if (!project) continue;
649	
650				const hostType: DashboardSidebarWorkspace["hostType"] =
651					workspace.hostId === machineId ? "local-device" : "remote-device";
652	
653				const sidebarWorkspace: DashboardSidebarWorkspace = {
654					id: workspace.id,
655					projectId: workspace.projectId,
656					hostId: workspace.hostId,
657					hostType,
658					type: workspace.type,
659					hostIsOnline:
660						hostType === "remote-device" ? workspace.hostIsOnline : null,
661					accentColor: null,
662					name: workspace.name,
663					branch: workspace.branch,
664					pullRequest: pullRequestsByWorkspaceId.get(workspace.id) ?? null,
665					repoUrl:
666						project.githubOwner && project.githubRepoName
667							? `https://github.com/${project.githubOwner}/${project.githubRepoName}`
668							: null,
669					branchExistsOnRemote:
670						project.githubOwner !== null && project.githubRepoName !== null,
671					previewUrl: null,
672					needsRebase: null,
673					behindCount: null,
674					createdAt: workspace.createdAt,
675					updatedAt: workspace.updatedAt,
676					taskId: workspace.taskId,
677					pendingTransaction: workspace.pendingTransaction,
678					justReturned: justReturnedIds.has(workspace.id),
679				};
680	
681				if (workspace.sectionId) {
682					const section = project.sectionMap.get(workspace.sectionId);
683					if (section) {
684						section.workspaces.push({
685							...sidebarWorkspace,
686							accentColor: section.color,
687						});
688						continue;
689					}
690					// Section was deleted out from under this workspace — surface it at
691					// top level instead of silently dropping it.
692					project.orphanedWorkspaces.push({
693						tabOrder: workspace.tabOrder,
694						workspace: sidebarWorkspace,
695					});
696					continue;
697				}
698	
699				project.childEntries.push({
700					tabOrder: workspace.tabOrder,
701					child: {
702						type: "workspace",
703						workspace: sidebarWorkspace,
704					},
705				});
706			}
707	
708			const buildInactiveWorkspace = (
709				workspace: (typeof snoozedSidebarWorkspaces)[number],
710				project: DashboardSidebarProject,
711			): DashboardSidebarWorkspace => {
712				const hostType: DashboardSidebarWorkspace["hostType"] =
713					workspace.hostId === machineId ? "local-device" : "remote-device";
714				return {
715					id: workspace.id,
716					projectId: workspace.projectId,
717					hostId: workspace.hostId,
718					hostType,
719					type: workspace.type,
720					hostIsOnline:
721						hostType === "remote-device" ? workspace.hostIsOnline : null,
722					accentColor: null,
723					name: workspace.name,
724					branch: workspace.branch,
725					pullRequest: null,
726					repoUrl:
727						project.githubOwner && project.githubRepoName
728							? `https://github.com/${project.githubOwner}/${project.githubRepoName}`
729							: null,
730					branchExistsOnRemote:
731						project.githubOwner !== null && project.githubRepoName !== null,
732					previewUrl: null,
733					needsRebase: null,
734					behindCount: null,
735					createdAt: workspace.createdAt,
736					updatedAt: workspace.updatedAt,
737					taskId: workspace.taskId,
738					pendingTransaction: workspace.pendingTransaction,
739					snoozeUntil: workspace.snoozeUntil ?? null,
740					snoozeLaunchId: workspace.snoozeLaunchId ?? null,
741					archivedAt: workspace.archivedAt ?? null,
742					// (RECYCLE-BIN) carried so the Recycle Bin section can sort by it and
743					// apply the retention "Show all" filter.
744					deletedAt: workspace.deletedAt ?? null,
745					snoozeRemainingLabel: formatSnoozeRemaining(
746						workspace.snoozeUntil,
747						workspace.snoozeLaunchId,
748						nowMs,
749					),
750				};
751			};
752	
753			for (const workspace of snoozedSidebarWorkspaces) {
754				const project = projectsById.get(workspace.projectId);
755				if (!project) continue;
756				project.snoozedWorkspaces.push(
757					buildInactiveWorkspace(workspace, project),
758				);
759			}
760	
761			for (const workspace of archivedSidebarWorkspaces) {
762				const project = projectsById.get(workspace.projectId);
763				if (!project) continue;
764				project.archivedWorkspaces.push(
765					buildInactiveWorkspace(workspace, project),
766				);
767			}
768	
769			for (const workspace of deletedSidebarWorkspaces) {
770				const project = projectsById.get(workspace.projectId);
771				if (!project) continue;
772				project.deletedWorkspaces.push(
773					buildInactiveWorkspace(workspace, project),
774				);
775			}
776	
777			return sidebarProjects.flatMap((project) => {
778				const resolvedProject = projectsById.get(project.id);
779				if (!resolvedProject) return [];
780				const {
781					childEntries,
782					sectionMap: _sectionMap,
783					orphanedWorkspaces,
784					...sidebarProject
785				} = resolvedProject;
786	
787				const isLocalMain = (entry: (typeof childEntries)[number]) =>
788					entry.child.type === "workspace" &&
789					entry.child.workspace.type === "main" &&
790					entry.child.workspace.hostType === "local-device";
791	
792				const sortedChildren = childEntries
793					.sort((left, right) => {
794						const leftLocalMain = isLocalMain(left);
795						const rightLocalMain = isLocalMain(right);
796						if (leftLocalMain !== rightLocalMain) {
797							return leftLocalMain ? -1 : 1;
798						}
799						return left.tabOrder - right.tabOrder;
800					})
801					.map(({ child }) => child);
802	
803				// Ungrouped workspaces rendered after a section header are visually
804				// grouped with that section (shared accent, collapse-together) and will
805				// be committed into it on next DnD. Reparent them here so section counts
806				// match what the user sees.
807				const children: DashboardSidebarProjectChild[] = [];
808				let currentSection: DashboardSidebarSection | null = null;
809				for (const child of sortedChildren) {
810					if (child.type === "section") {
811						currentSection = child.section;
812						children.push(child);
813					} else if (currentSection) {
814						currentSection.workspaces.push({
815							...child.workspace,
816							accentColor: currentSection.color,
817						});
818					} else {
819						children.push(child);
820					}
821				}
822	
823				// Workspaces whose section was deleted (orphaned) render above the
824				// first section so they stay visible instead of vanishing.
825				if (orphanedWorkspaces.length > 0) {
826					const isLocalMainWorkspace = (workspace: DashboardSidebarWorkspace) =>
827						workspace.type === "main" && workspace.hostType === "local-device";
828					const firstSectionIndex = children.findIndex(
829						(child) => child.type === "section",
830					);
831					const insertIndex =
832						firstSectionIndex === -1 ? children.length : firstSectionIndex;
833					children.splice(
834						insertIndex,
835						0,
836						...orphanedWorkspaces
837							.sort((left, right) => {
838								const leftLocalMain = isLocalMainWorkspace(left.workspace);
839								const rightLocalMain = isLocalMainWorkspace(right.workspace);
840								if (leftLocalMain !== rightLocalMain) {
841									return leftLocalMain ? -1 : 1;
842								}
843								return left.tabOrder - right.tabOrder;
844							})
845							.map(({ workspace }) => ({
846								type: "workspace" as const,
847								workspace,
848							})),
849					);
850				}
851	
852				sidebarProject.children = children;
853				sidebarProject.snoozedWorkspaces.sort(
854					(left, right) =>
855						(left.snoozeUntil ?? Number.MAX_SAFE_INTEGER) -
856						(right.snoozeUntil ?? Number.MAX_SAFE_INTEGER),
857				);
858				sidebarProject.archivedWorkspaces.sort(
859					(left, right) => (right.archivedAt ?? 0) - (left.archivedAt ?? 0),
860				);
861				// (RECYCLE-BIN) most-recently-deleted first.
862				sidebarProject.deletedWorkspaces.sort(
863					(left, right) => (right.deletedAt ?? 0) - (left.deletedAt ?? 0),
864				);
865				return [sidebarProject];
866			});
867		}, [
868			machineId,
869			nowMs,
870			justReturnedIds,
871			pullRequestsByWorkspaceId,
872			sidebarProjects,
873			sidebarSections,
874			visibleSidebarWorkspaces,
875			snoozedSidebarWorkspaces,
876			archivedSidebarWorkspaces,
877			deletedSidebarWorkspaces,
878		]);
879		const groups = useStableDashboardSidebarProjects(computedGroups);
880	
881		return {
882			groups,
883			refreshWorkspacePullRequest,
884			toggleProjectCollapsed,
885		};
886	}
