1	import type { ExternalApp } from "@superset/local-db";
2	import { eq } from "@tanstack/db";
3	import { useLiveQuery } from "@tanstack/react-db";
4	import { useCallback } from "react";
5	import { useDashboardSidebarState } from "renderer/routes/_authenticated/hooks/useDashboardSidebarState";
6	import { useCollections } from "renderer/routes/_authenticated/providers/CollectionsProvider";
7	
8	/**
9	 * Single source of truth for the v2 per-project "open in" app choice —
10	 * the value the user picked via the CMD+O menu in `V2OpenInMenuButton`.
11	 *
12	 * v2 stores this client-side in `v2SidebarProjects.defaultOpenInApp`
13	 * (tanstack-db) because v2 projects are not in the v1 localDb tables
14	 * that the server-side `resolveDefaultEditor` consults. Anywhere v2 code
15	 * needs to read or write this preference should go through this hook so
16	 * CMD+O and file-open flows stay in sync.
17	 */
18	export function useV2ProjectDefaultApp(projectId: string | undefined) {
19		const collections = useCollections();
20		const { ensureProjectInSidebar } = useDashboardSidebarState();
21	
22		const { data: rows = [] } = useLiveQuery(
23			(q) =>
24				q
25					.from({ sp: collections.v2SidebarProjects })
26					.where(({ sp }) => eq(sp.projectId, projectId ?? ""))
27					.select(({ sp }) => ({ defaultOpenInApp: sp.defaultOpenInApp })),
28			[collections, projectId],
29		);
30		const app =
31			(rows[0]?.defaultOpenInApp as ExternalApp | null | undefined) ?? undefined;
32	
33		const setApp = useCallback(
34			(next: ExternalApp) => {
35				if (!projectId) return;
36				ensureProjectInSidebar(projectId);
37				collections.v2SidebarProjects.update(projectId, (draft) => {
38					draft.defaultOpenInApp = next;
39				});
40			},
