1	import type { SelectV2Workspace } from "@superset/db/schema";
2	import type { WorkspaceState } from "@superset/panes";
3	import type { PaneLifecycleRow } from "renderer/routes/_authenticated/components/utils/paneLifecycleRows";
4	import type { AppCollections } from "renderer/routes/_authenticated/providers/CollectionsProvider/collections";
5	
6	export type SidebarWorkspaceRow = Pick<
7		SelectV2Workspace,
8		"id" | "projectId" | "type" | "hostId"
9	>;
10	
11	/**
12	 * Pure sidebar local-state mutations, kept free of React/Electron imports so
13	 * they can be unit-tested against an in-memory collection. Pane-runtime cleanup
14	 * is injected so the registry side effects stay in the hook layer.
15	 */
16	
17	export function createEmptyPaneLayout(): WorkspaceState<unknown> {
18		return {
19			version: 1,
20			tabs: [],
21			activeTabId: null,
22		} satisfies WorkspaceState<unknown>;
23	}
24	
25	type CleanupPaneRuntimes = (rows: PaneLifecycleRow[]) => void;
26	
27	/**
28	 * Hides a single workspace while keeping its project in the sidebar, by leaving
29	 * a hidden "tombstone" row rather than deleting it. A local `main` workspace
30	 * with no local-state row is re-surfaced by the gated auto-include path, so
31	 * hiding one requires a row (`isHidden: true`) to suppress it; a hard-delete
32	 * would let it reappear.
33	 */
34	export function tombstoneSidebarWorkspaceRecord(
35		collections: Pick<AppCollections, "v2WorkspaceLocalState">,
36		workspaceId: string,
37		projectId: string,
38		cleanupPaneRuntimes: CleanupPaneRuntimes,
39	): void {
40		const existing = collections.v2WorkspaceLocalState.get(workspaceId);
41		if (!existing) {
42			collections.v2WorkspaceLocalState.insert({
43				workspaceId,
44				createdAt: new Date(),
45				sidebarState: {
46					projectId,
47					tabOrder: 0,
48					sectionId: null,
49					isHidden: true,
50				},
51				paneLayout: createEmptyPaneLayout(),
52			});
53			return;
54		}
55	
56		cleanupPaneRuntimes([existing]);
57		collections.v2WorkspaceLocalState.update(workspaceId, (draft) => {
58			draft.sidebarState.projectId = projectId;
59			draft.sidebarState.sectionId = null;
60			draft.sidebarState.isHidden = true;
61			draft.paneLayout = createEmptyPaneLayout();
62		});
63	}
64	
65	/**
66	 * Removes a project from the sidebar. Deleting its `v2SidebarProjects` row is
67	 * what hides it: membership is explicit and display gates on it
68	 * (`buildDashboardSidebarProjects` drops any workspace whose project is absent).
69	 *
70	 * Worktrees are tombstoned so "removed" stays removed. A worktree with no
71	 * local-state row would be re-placed by `usePlaceLocalWorktreesInSidebar`
72	 * (recreating the project), and a kept-but-visible row would flood back the
73	 * moment anything recreates the project row — e.g. a later automation-created
74	 * worktree. Hiding each one (existing rows, plus this device's row-less
75	 * worktrees the reconciler could re-pin) means a resurrected project shows only
76	 * the genuinely-new worktree, not these dismissed ones.
77	 *
78	 * `main` workspaces are intentionally left alone: they surface via the gated
79	 * auto-include path (never re-pinned, never create a project record), so
80	 * deleting the project row already hides them and re-adding the project brings
81	 * the main back. Removing a project discards `defaultOpenInApp` (stored on the
82	 * project row and nowhere else); it resets to default on re-add.
83	 */
84	export function removeProjectFromSidebarState(
85		collections: Pick<
86			AppCollections,
87			"v2WorkspaceLocalState" | "v2SidebarSections" | "v2SidebarProjects"
88		>,
89		workspaces: SidebarWorkspaceRow[],
90		projectId: string,
91		machineId: string,
92		cleanupPaneRuntimes: CleanupPaneRuntimes,
93	): void {
94		const mainWorkspaceIds = new Set(
95			workspaces
96				.filter((ws) => ws.projectId === projectId && ws.type === "main")
97				.map((ws) => ws.id),
98		);
99	
100		const worktreeIds = new Set<string>();
101		for (const row of collections.v2WorkspaceLocalState.state.values()) {
102			if (
103				row.sidebarState.projectId === projectId &&
104				!mainWorkspaceIds.has(row.workspaceId)
105			) {
106				worktreeIds.add(row.workspaceId);
107			}
108		}
109		for (const ws of workspaces) {
110			if (
111				ws.projectId === projectId &&
112				ws.type === "worktree" &&
113				ws.hostId === machineId
114			) {
115				worktreeIds.add(ws.id);
116			}
117		}
118	
119		for (const workspaceId of worktreeIds) {
120			tombstoneSidebarWorkspaceRecord(
121				collections,
122				workspaceId,
123				projectId,
124				cleanupPaneRuntimes,
125			);
126		}
127	
128		const sectionIds = Array.from(collections.v2SidebarSections.state.values())
129			.filter((item) => item.projectId === projectId)
130			.map((item) => item.sectionId);
131		if (sectionIds.length > 0) {
132			collections.v2SidebarSections.delete(sectionIds);
133		}
134	
135		if (collections.v2SidebarProjects.get(projectId)) {
136			collections.v2SidebarProjects.delete(projectId);
137		}
138	}
