1	import { toast } from "@superset/ui/sonner";
2	import {
3		useMatchRoute,
4		useNavigate,
5		useRouterState,
6	} from "@tanstack/react-router";
7	import { useState } from "react";
8	import {
9		useMarkWorkspaceTerminalsSeen,
10		useV2WorkspaceIsUnread,
11	} from "renderer/hooks/host-service/useV2NotificationStatus";
12	import { useCopyToClipboard } from "renderer/hooks/useCopyToClipboard";
13	import { getHostServiceClientByUrl } from "renderer/lib/host-service-client";
14	import { showHostServiceUnavailableToast } from "renderer/lib/host-service-unavailable";
15	import { electronTrpcClient } from "renderer/lib/trpc-client";
16	import { useDashboardSidebarSectionRename } from "renderer/routes/_authenticated/_dashboard/components/DashboardSidebar/components/DashboardSidebarSectionRenameContext";
17	import { useDashboardSidebarState } from "renderer/routes/_authenticated/hooks/useDashboardSidebarState";
