20		computeSnoozeUntil,
21		type SnoozeDuration,
22	} from "renderer/routes/_authenticated/providers/CollectionsProvider/dashboardSidebarLocal";
23	import { useLocalHostService } from "renderer/routes/_authenticated/providers/LocalHostServiceProvider";
24	import { useRemoveFromSidebarIntent } from "renderer/stores/remove-workspace-from-sidebar-intent";
25	import { useV2NotificationStore } from "renderer/stores/v2-notifications";
26	
27	interface UseDashboardSidebarWorkspaceItemActionsOptions {
28		workspaceId: string;
29		projectId: string;
30		workspaceName: string;
31		branch: string;
32		isMainWorkspace?: boolean;
33	}
34	
35	export function useDashboardSidebarWorkspaceItemActions({
36		workspaceId,
37		projectId,
38		workspaceName,
39		branch,
40		isMainWorkspace = false,
41	}: UseDashboardSidebarWorkspaceItemActionsOptions) {
42		const navigate = useNavigate();
43		const matchRoute = useMatchRoute();
44		const hostService = useLocalHostService();
45		const { activeHostUrl } = hostService;
46		const { copyToClipboard } = useCopyToClipboard();
47		const { v2Workspaces: workspaceActions } = useOptimisticCollectionActions();
48		const { requestSectionRename } = useDashboardSidebarSectionRename();
49		const setManualUnread = useV2NotificationStore((s) => s.setManualUnread);
50		const clearManualUnread = useV2NotificationStore((s) => s.clearManualUnread);
51		const markWorkspaceTerminalsSeen = useMarkWorkspaceTerminalsSeen(workspaceId);
52		const isUnread = useV2WorkspaceIsUnread(workspaceId);
53		const clearWorkspaceAttention = () => {
54			clearManualUnread(workspaceId);
55			markWorkspaceTerminalsSeen();
56		};
57		const {
58			archiveWorkspace,
59			createSection,
60			deleteWorkspace,
61			moveWorkspaceToSection,
62			removeWorkspaceFromSidebar,
63			restoreWorkspace,
64			snoozeWorkspace,
65			unarchiveWorkspace,
66			unsnoozeWorkspace,
67		} = useDashboardSidebarState();
68	
69		const [isRenaming, setIsRenaming] = useState(false);
70		const [renameValue, setRenameValue] = useState(workspaceName);
71		const [isDeleteDialogOpen, setIsDeleteDialogOpen] = useState(false);
72	
73		// (KANBAN) When the kanban view is showing, sidebar selection opens the
74		// workspace INSIDE the collapse-split (board rail stays) instead of
75		// navigating away from the board.
76		const onKanban = !!matchRoute({ to: "/kanban", fuzzy: true });
77		const kanbanOpenWorkspaceId = useRouterState({
78			select: (s) => (s.location.search as { cardId?: string }).cardId,
79		});
80	
81		const isActive =
82			!!matchRoute({
83				to: "/v2-workspace/$workspaceId",
84				params: { workspaceId },
85				fuzzy: true,
86			}) ||
87			(onKanban && kanbanOpenWorkspaceId === workspaceId);
88	
89		const handleClick = () => {
90			if (isRenaming) return;
91			// Per-tab mark-as-read: workspace click navigates only. The
92			// downstream useClearActivePaneAttention hook clears just the
93			// active terminal's source on focus, so unfocused terminals keep
94			// their unread dot until the user actually visits them — matching
95			// the per-terminal-dots indicator we render in the sidebar row.
96			if (onKanban) {
97				navigate({ to: "/kanban", search: { cardId: workspaceId } });
98				return;
99			}
100			navigate({
101				to: "/v2-workspace/$workspaceId",
102				params: { workspaceId },
103			});
104		};
105	
106		const startRename = () => {
107			setRenameValue(workspaceName);
108			setIsRenaming(true);
109		};
110	
111		const cancelRename = () => {
112			setIsRenaming(false);
113			setRenameValue(workspaceName);
114		};
115	
116		const submitRename = () => {
117			setIsRenaming(false);
118			const trimmed = renameValue.trim();
119			if (!trimmed || trimmed === workspaceName) return;
120			workspaceActions.renameWorkspace(workspaceId, trimmed);
121		};
122	
123		const handleDeleted = () => {
124			removeWorkspaceFromSidebar(workspaceId);
125		};
126	
127		const handleRemoveFromSidebar = () => {
128			useRemoveFromSidebarIntent.getState().request({
129				workspaceId,
130				workspaceName,
131				projectId,
132				isMain: isMainWorkspace,
133			});
134		};
135	
136		const handleSnooze = (duration: SnoozeDuration) => {
137			snoozeWorkspace(workspaceId, computeSnoozeUntil(duration));
138		};
139	
140		const handleUnsnooze = () => {
141			unsnoozeWorkspace(workspaceId);
142		};
143	
144		const handleArchive = () => {
145			archiveWorkspace(workspaceId);
146		};
147	
148		const handleUnarchive = () => {
149			unarchiveWorkspace(workspaceId);
150		};
151	
152		// (RECYCLE-BIN) The default-mode Delete is now a SILENT soft-delete — no
153		// dialog, no toast — moving the thread to the project's Recycle Bin. The real
154		// git destroy lives behind "Delete permanently" inside the bin (the existing
155		// destroy dialog, opened via setIsDeleteDialogOpen).
156		const handleDelete = () => {
157			deleteWorkspace(workspaceId, projectId);
158		};
159	
160		const handleRestore = () => {
161			restoreWorkspace(workspaceId);
162		};
163	
164		const handleCreateSection = () => {
165			const sectionId = createSection(projectId);
166			moveWorkspaceToSection(workspaceId, projectId, sectionId);
167			requestSectionRename(sectionId);
168		};
169	
170		const resolveWorktreePath = async (): Promise<string | null> => {
171			if (!activeHostUrl) {
172				showHostServiceUnavailableToast(hostService, {
173					action: "resolve the workspace path",
174				});
175				return null;
176			}
177			const workspace = await getHostServiceClientByUrl(
178				activeHostUrl,
179			).workspace.get.query({ id: workspaceId });
180			if (!workspace?.worktreePath) {
181				toast.error("Workspace path is not available");
182				return null;
183			}
184			return workspace.worktreePath;
185		};
186	
187		const handleOpenInFinder = async () => {
188			try {
189				const path = await resolveWorktreePath();
190				if (!path) return;
191				await electronTrpcClient.external.openInFinder.mutate(path);
192			} catch (error) {
193				toast.error(
194					`Failed to open in Finder: ${error instanceof Error ? error.message : "Unknown error"}`,
195				);
196			}
197		};
198	
199		const handleCopyPath = async () => {
200			try {
201				const path = await resolveWorktreePath();
202				if (!path) return;
203				await copyToClipboard(path);
204				toast.success("Path copied");
205			} catch (error) {
206				toast.error(
207					`Failed to copy path: ${error instanceof Error ? error.message : "Unknown error"}`,
208				);
209			}
210		};
211	
212		const handleToggleUnread = () => {
213			if (isUnread) {
214				clearWorkspaceAttention();
215			} else {
216				setManualUnread(workspaceId);
217			}
218		};
219	
220		// Working/permission dots are live host state now and can't be wiped;
221		// "clear status" clears everything attention-shaped (manual + reviews).
222		const handleClearStatus = () => {
223			clearWorkspaceAttention();
224		};
225	
226		const handleCopyBranchName = async () => {
227			if (!branch) {
228				toast.error("Branch name is not available");
229				return;
230			}
231			try {
232				await copyToClipboard(branch);
233				toast.success("Branch name copied");
234			} catch (error) {
235				toast.error(
236					`Failed to copy branch name: ${error instanceof Error ? error.message : "Unknown error"}`,
237				);
238			}
239		};
240	
241		return {
242			cancelRename,
243			handleClearStatus,
244			handleClick,
245			handleCopyPath,
246			handleCopyBranchName,
247			handleCreateSection,
248			handleDelete,
249			handleDeleted,
250			handleArchive,
251			handleOpenInFinder,
252			handleRemoveFromSidebar,
253			handleRestore,
254			handleSnooze,
255			handleToggleUnread,
256			handleUnarchive,
257			handleUnsnooze,
258			isActive,
259			isDeleteDialogOpen,
260			isRenaming,
261			isUnread,
262			moveWorkspaceToSection,
263			renameValue,
264			setIsDeleteDialogOpen,
265			setRenameValue,
266			startRename,
267			submitRename,
268		};
269	}
