1	import { describe, expect, it } from "bun:test";
2	import {
3		removeProjectFromSidebarState,
4		type SidebarWorkspaceRow,
5		tombstoneSidebarWorkspaceRecord,
6	} from "./sidebarMutations";
7	
8	/**
9	 * Minimal in-memory stand-in for a TanStack DB collection, implementing only
10	 * the surface the sidebar mutations touch (`get`/`insert`/`update`/`delete`
11	 * plus a `.state` Map).
12	 */
13	function makeCollection<T>(getKey: (item: T) => string) {
14		const state = new Map<string, T>();
15		return {
16			state,
17			get: (key: string) => state.get(key),
18			insert: (item: T) => {
19				state.set(getKey(item), structuredClone(item));
20			},
21			update: (key: string, producer: (draft: T) => void) => {
22				const existing = state.get(key);
23				if (!existing) return;
24				const draft = structuredClone(existing);
25				producer(draft);
26				state.set(key, draft);
27			},
28			delete: (keys: string | string[]) => {
29				for (const key of Array.isArray(keys) ? keys : [keys]) {
30					state.delete(key);
31				}
32			},
33		};
34	}
35	
36	type LocalStateRow = {
37		workspaceId: string;
38		createdAt: Date;
39		sidebarState: {
40			projectId: string;
41			tabOrder: number;
42			sectionId: string | null;
43			isHidden: boolean;
44		};
45		paneLayout: { version: number; tabs: unknown[]; activeTabId: string | null };
46	};
47	
48	function localStateRow(
49		workspaceId: string,
50		projectId: string,
51		overrides: Partial<LocalStateRow["sidebarState"]> = {},
52	): LocalStateRow {
53		return {
54			workspaceId,
55			createdAt: new Date("2026-01-01T00:00:00.000Z"),
56			sidebarState: {
57				projectId,
58				tabOrder: 1,
59				sectionId: null,
60				isHidden: false,
61				...overrides,
62			},
63			paneLayout: { version: 1, tabs: [], activeTabId: null },
64		};
65	}
66	
67	function makeCollections() {
68		return {
69			v2WorkspaceLocalState: makeCollection<LocalStateRow>(
70				(row) => row.workspaceId,
71			),
72			v2SidebarSections: makeCollection<{
73				sectionId: string;
74				projectId: string;
75			}>((row) => row.sectionId),
76			v2SidebarProjects: makeCollection<{ projectId: string }>(
77				(row) => row.projectId,
78			),
79		};
80	}
81	
82	type Collections = ReturnType<typeof makeCollections>;
83	
84	// The functions accept the real `AppCollections` Pick; our fakes implement the
85	// touched subset, so cast through the parameter type.
86	function asRemoveArg(collections: Collections) {
87		return collections as unknown as Parameters<
88			typeof removeProjectFromSidebarState
89		>[0];
90	}
91	function asTombstoneArg(collections: Collections) {
92		return collections as unknown as Parameters<
93			typeof tombstoneSidebarWorkspaceRecord
94		>[0];
95	}
96	
97	const noopCleanup = () => {};
98	
99	describe("removeProjectFromSidebarState", () => {
100		it("tombstones the project's worktrees — existing rows and this device's row-less ones — and deletes sections and the project record", () => {
101			const collections = makeCollections();
102			// Explicitly-placed worktree (has a visible local-state row).
103			collections.v2WorkspaceLocalState.insert(
104				localStateRow("ws-placed", "proj-1", { sectionId: "sec-1" }),
105			);
106			const workspaces: SidebarWorkspaceRow[] = [
107				{
108					id: "ws-placed",
109					projectId: "proj-1",
110					hostId: "machine-1",
111					type: "worktree",
112				},
113				// This device's worktree with no row yet — the reconciler would re-pin it.
114				{
115					id: "ws-rowless",
116					projectId: "proj-1",
117					hostId: "machine-1",
118					type: "worktree",
119				},
120			];
121			collections.v2SidebarSections.insert({
122				sectionId: "sec-1",
123				projectId: "proj-1",
124			});
125			collections.v2SidebarProjects.insert({ projectId: "proj-1" });
126	
127			const cleaned: string[] = [];
128			removeProjectFromSidebarState(
129				asRemoveArg(collections),
130				workspaces,
131				"proj-1",
132				"machine-1",
133				(rows) => {
134					for (const row of rows) cleaned.push(String(row.workspaceId));
135				},
136			);
137	
138			// Existing row hidden (kept); row-less worktree gets an inserted tombstone.
139			expect(
140				collections.v2WorkspaceLocalState.get("ws-placed")?.sidebarState.isHidden,
141			).toBe(true);
142			expect(
143				collections.v2WorkspaceLocalState.get("ws-rowless")?.sidebarState
144					.isHidden,
145			).toBe(true);
146			expect(collections.v2SidebarSections.get("sec-1")).toBeUndefined();
147			expect(collections.v2SidebarProjects.get("proj-1")).toBeUndefined();
148			// Only the pre-existing row had live runtimes to tear down.
149			expect(cleaned).toEqual(["ws-placed"]);
150		});
151	
152		it("leaves the project's main workspace alone so re-adding the project restores it", () => {
153			const collections = makeCollections();
154			collections.v2WorkspaceLocalState.insert(
155				localStateRow("ws-main", "proj-1"),
156			);
157			const workspaces: SidebarWorkspaceRow[] = [
158				{ id: "ws-main", projectId: "proj-1", hostId: "machine-1", type: "main" },
159				{
160					id: "ws-main-rowless",
161					projectId: "proj-1",
162					hostId: "machine-1",
163					type: "main",
164				},
165			];
166			collections.v2SidebarProjects.insert({ projectId: "proj-1" });
167	
168			removeProjectFromSidebarState(
169				asRemoveArg(collections),
170				workspaces,
171				"proj-1",
172				"machine-1",
173				noopCleanup,
174			);
175	
176			// Main row untouched (not hidden); no tombstone created for a row-less main.
177			expect(
178				collections.v2WorkspaceLocalState.get("ws-main")?.sidebarState.isHidden,
179			).toBe(false);
180			expect(
181				collections.v2WorkspaceLocalState.get("ws-main-rowless"),
182			).toBeUndefined();
183			expect(collections.v2SidebarProjects.get("proj-1")).toBeUndefined();
184		});
185	
186		it("leaves workspaces from other projects untouched", () => {
187			const collections = makeCollections();
188			collections.v2WorkspaceLocalState.insert(
189				localStateRow("ws-other", "proj-2"),
190			);
191			const workspaces: SidebarWorkspaceRow[] = [
