// ---------------------------------------------------------------------------
// (KANBAN) Local-only board: columns + cards.
//
// A single device-local Kanban that mirrors every branch (workspace) as a card
// plus user-created "Queued" task cards. Local-only like every other v2 sidebar
// UI-state collection — no server/Electric/Drizzle, created on first use, healed
// on read. See feature_plan_kanban-board.html.
//
// Snooze/archive: for a BOUND card (workspaceId set) the visibility comes from
// the branch's sidebarState (one source of truth) — the card's own snooze/
// archive fields are used ONLY for unbound (Queued) cards.
// ---------------------------------------------------------------------------

export const kanbanColumnSchema = z.object({
	id: z.string(),
	name: z.string().default(""),
	tabOrder: z.number().int().default(0),
	// Exactly one column is the fixed first "Queued" column (unbound tasks only).
	// Healed/seeded with a deterministic id (see kanbanQueueColumnId).
	isQueue: z.boolean().default(false),
	// Exactly one column is the fixed FINAL "Completed" column. Cards dropped
	// there are stamped done (see card.completedAt); the column can't be moved
	// or deleted. Healed/seeded from KANBAN_COMPLETED_COLUMN_ID like the queue.
	isCompleted: z.boolean().default(false),
	// (KANBAN COMPLETED) Per-column completed-date filter — only meaningful on
	// the Completed column. "last-month" = previous calendar month; "custom"
	// uses the local-midnight from/to bounds (inclusive days).
	completedFilter: z.enum(["all", "last-month", "custom"]).default("all"),
	completedFilterFrom: z.number().nullable().default(null),
	completedFilterTo: z.number().nullable().default(null),
	// Display-only sort. NEVER rewrites card tabOrder — flipping back to "manual"
	// restores the manual drag order untouched.
	sortMode: z.enum(["manual", "deadline"]).default("manual"),
	// Per-column Snoozed / Archived section reveal + collapse (mirrors the
	// project-level section flags on dashboardSidebarProjectSchema).
	showSnoozed: z.boolean().default(false),
	showArchived: z.boolean().default(false),
	snoozedCollapsed: z.boolean().default(false),
	archivedCollapsed: z.boolean().default(false),
	// (RECYCLE-BIN) Per-column reveal + collapse for the Recycle Bin sub-section
	// (soft-deleted cards), mirroring the Snoozed / Archived flags above.
	showRecycleBin: z.boolean().default(false),
	recycleBinCollapsed: z.boolean().default(false),
	createdAt: z.number().default(0),
});

export type KanbanColumnRow = z.infer<typeof kanbanColumnSchema>;

export const kanbanCardSchema = z.object({
	// BOUND cards use a deterministic id `workspace:<workspaceId>` so reconcile /
	// promote / merge can never create two cards for one branch. Queued
	// (unbound) cards use a uuid.
	id: z.string(),
	columnId: z.string(),
	tabOrder: z.number().int().default(0),
	title: z.string().default(""),
	description: z.string().nullable().default(null),
	// Date-only deadline stored as local-midnight epoch-ms (null = none).
	deadline: z.number().nullable().default(null),
	// (DEADLINE-TIE-ORDER) Manual order WITHIN a deadline tie group (same due
	// day, or the no-deadline tail) while the column is deadline-sorted. Kept
	// separate from tabOrder so deadline-mode drags never scramble the manual
	// order (and vice versa). null = never ordered there → renders BELOW the
	// explicitly ordered cards of its group; reset to null whenever the card's
	// deadline changes or it moves column (it "arrives" as a new item).
	deadlineTabOrder: z.number().int().nullable().default(null),
	// null = Queued / unbound; set = bound to a branch (workspace).
	workspaceId: z.string().nullable().default(null),
	// Used ONLY when unbound. Bound cards derive snooze/archive from the branch's
	// sidebarState — these stay null for them.
	snoozeUntil: z.number().nullable().default(null),
	snoozeLaunchId: z.string().nullable().default(null),
	archivedAt: z.number().nullable().default(null),
	// (KANBAN COMPLETED) When the card was LAST dropped into the Completed
	// column (epoch-ms; date-editable afterwards). The report datum for ALL
	// cards — for bound cards the branch's sidebarState.completedAt is only the
	// sidebar-visibility flag; this card field is what's displayed, filtered,
	// sorted and (via the daily append-only backup) preserved.
	completedAt: z.number().nullable().default(null),
	// "project / branch" snapshot taken at completion — the subtitle a FROZEN
	// record (completed card whose branch was later deleted) renders, since the
	// live workspace row is gone.
	completedContext: z.string().nullable().default(null),
	// (RECYCLE-BIN) Soft-delete timestamp for an UNBOUND (Queued) card. Bound
	// cards derive their bin state from the branch's sidebarState.deletedAt (one
	// source of truth) — this stays null for them. Set by deleteCard, cleared by
	// restoreCard; permanent removal still hard-deletes the row.
	deletedAt: z.number().nullable().default(null),
	createdAt: z.number().default(0),
});

export type KanbanCardRow = z.infer<typeof kanbanCardSchema>;

// Deterministic ids — the invariants ("exactly one queue", "one card per
// branch") are enforced by id, not just Zod defaults (localStorage reads skip
// defaults; see withReadHeal).
export const KANBAN_BOUND_CARD_PREFIX = "workspace:";

export function kanbanBoundCardId(workspaceId: string): string {
	return `${KANBAN_BOUND_CARD_PREFIX}${workspaceId}`;
}

/** The fixed first "Queued" column id. Constant (not per-org) because the
 * collection's storageKey is already org-scoped, so this is unique within each
 * org's board. Seeded/healed to exactly one. */
export const KANBAN_QUEUE_COLUMN_ID = "queue";

/** tabOrder reserved for the Queued column — always sorts first. */
export const KANBAN_QUEUE_TAB_ORDER = -1_000_000;

/** The fixed FINAL "Completed" column id. Constant (not per-org) because the
 * collection's storageKey is already org-scoped. Seeded/healed to exactly one. */
export const KANBAN_COMPLETED_COLUMN_ID = "completed";

/** tabOrder reserved for the Completed column — always sorts last. */
export const KANBAN_COMPLETED_TAB_ORDER = 1_000_000;

const KANBAN_COLUMN_DEFAULTS = {
	name: "",
	tabOrder: 0,
	isQueue: false,
	isCompleted: false,
	sortMode: "manual",
	completedFilter: "all",
	completedFilterFrom: null,
	completedFilterTo: null,
	showSnoozed: false,
	showArchived: false,
	snoozedCollapsed: false,
	archivedCollapsed: false,
	showRecycleBin: false,
	recycleBinCollapsed: false,
	createdAt: 0,
} as const;

const KANBAN_CARD_DEFAULTS = {
	tabOrder: 0,
	title: "",
	description: null,
	deadline: null,
	deadlineTabOrder: null,
	workspaceId: null,
	snoozeUntil: null,
	snoozeLaunchId: null,
	archivedAt: null,
	completedAt: null,
	completedContext: null,
	deletedAt: null,
	createdAt: 0,
} as const;

/** Heal a stored Kanban column row — merges defaults so rows persisted before a
 * field existed read back normalized (identity field `id` passes through). */
export function healKanbanColumn(raw: unknown): KanbanColumnRow {
	const r = (
		raw && typeof raw === "object" ? raw : {}
	) as Partial<KanbanColumnRow>;
	const merged = { ...KANBAN_COLUMN_DEFAULTS, ...r } as KanbanColumnRow;
	// Derive the queue/completed flags from the deterministic ids (don't trust
	// the stored flags): guarantees exactly one of each and stops a stale row
	// hydrating as the wrong kind. Queue always sorts first, Completed last.
	merged.isQueue = merged.id === KANBAN_QUEUE_COLUMN_ID;
	if (merged.isQueue) merged.tabOrder = KANBAN_QUEUE_TAB_ORDER;
	merged.isCompleted = merged.id === KANBAN_COMPLETED_COLUMN_ID;
	if (merged.isCompleted) merged.tabOrder = KANBAN_COMPLETED_TAB_ORDER;
	return merged;
}

/** Heal a stored Kanban card row — merges defaults (identity fields `id` /
 * `columnId` pass through from the stored row). */
export function healKanbanCard(raw: unknown): KanbanCardRow {
	const r = (
		raw && typeof raw === "object" ? raw : {}
	) as Partial<KanbanCardRow>;
	return { ...KANBAN_CARD_DEFAULTS, ...r } as KanbanCardRow;
}
